-- {"operators": "INNER_JOIN,AGGREGATE,FILTER,DISTINCT", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,ITEM,OORDER,ORDER_LINE", "delta": true}
SELECT o.O_W_ID, COUNT(DISTINCT o.O_ID) AS orders, SUM(ol.OL_AMOUNT) AS revenue, AVG(i.I_PRICE) AS avg_item_price FROM d_OORDER o JOIN d_CUSTOMER c ON o.O_W_ID = c.C_W_ID AND o.O_D_ID = c.C_D_ID AND o.O_C_ID = c.C_ID JOIN d_ORDER_LINE ol ON o.O_W_ID = ol.OL_W_ID AND o.O_D_ID = ol.OL_D_ID AND o.O_ID = ol.OL_O_ID JOIN d_ITEM i ON ol.OL_I_ID = i.I_ID WHERE c.C_CREDIT = 'GC' GROUP BY o.O_W_ID;
